/**
 * Costing Routes
 *
 * REST endpoints for Total Cost of Ownership (TCO) projections and cost variance analysis.
 * Provides financial insights for the 12-year contract period.
 *
 * Key features:
 * - TCO projection with inflation and NPV calculations
 * - Budget vs. actual variance analysis
 * - Depot-level and global cost views
 *
 * @see specs/005-api.md Section 5.12
 */

import { Hono } from 'hono';
import {
  success,
  error,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import { getCostingService } from '../../services';
import { isValidUuid } from '../../lib/schemas';

// Singleton service instance
let costingService: ReturnType<typeof getCostingService> | null = null;

function getService(): ReturnType<typeof getCostingService> {
  if (!costingService) {
    costingService = getCostingService();
  }
  return costingService;
}

export const costingRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * GET /costing/tco-projection
 *
 * Get Total Cost of Ownership projection for the contract period.
 *
 * The projection includes:
 * - Yearly cost breakdown (labor + materials)
 * - Inflation adjustment (3% annually)
 * - NPV calculation (5% discount rate)
 * - PM count per year
 *
 * Query Parameters:
 * - horizonYears: Projection horizon in years (default: 12)
 * - scenarioId: Calculate for a specific scenario (UUID)
 * - depotId: Filter by depot (UUID)
 *
 * @returns TCO projection with yearly breakdown and summary
 */
costingRoutes.get('/costing/tco-projection', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  // Parse query parameters
  const horizonYearsParam = c.req.query('horizonYears');
  const scenarioId = c.req.query('scenarioId');
  const depotId = c.req.query('depotId');

  // Validate horizon years if provided
  let horizonYears: number | undefined;
  if (horizonYearsParam) {
    horizonYears = Number(horizonYearsParam);
    if (isNaN(horizonYears) || horizonYears < 1 || horizonYears > 20) {
      return c.json(
        error(
          ErrorCodes.VALIDATION_ERROR,
          'horizonYears must be between 1 and 20',
          requestId
        ),
        400
      );
    }
  }

  // Validate scenarioId if provided
  if (scenarioId && !isValidUuid(scenarioId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenarioId format', requestId),
      400
    );
  }

  // Validate depotId if provided
  if (depotId && !isValidUuid(depotId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid depotId format', requestId),
      400
    );
  }

  const projection = await service.projectTCO({
    horizonYears,
    scenarioId: scenarioId || undefined,
    depotId: depotId || undefined,
  });

  // Map to API response format per spec 005.12
  return c.json(
    success(
      {
        generatedAt: projection.calculatedAt.toISOString(),
        horizonYears: projection.horizonYears,
        projections: projection.projections.map((year) => ({
          fiscalYear: year.fiscalYear,
          laborCost: Math.round(year.laborCost * 100) / 100,
          materialCost: Math.round(year.materialCost * 100) / 100,
          totalCost: Math.round(year.totalCost * 100) / 100,
          pmCount: year.pmCount,
          inflationFactor: Math.round(year.inflationFactor * 10000) / 10000,
        })),
        summary: {
          totalLaborCost: Math.round(projection.summary.totalLaborCost * 100) / 100,
          totalMaterialCost: Math.round(projection.summary.totalMaterialCost * 100) / 100,
          totalCost: Math.round(projection.summary.totalCost * 100) / 100,
          totalPMCount: projection.summary.totalPMCount,
          npv: Math.round(projection.summary.npv * 100) / 100,
          avgAnnualCost: Math.round(projection.summary.avgAnnualCost * 100) / 100,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /costing/variance
 *
 * Get cost variance analysis comparing budget to actual costs.
 *
 * Compares:
 * - Budget figures from cost baseline
 * - Actual costs from completed PMs
 * - Variance with percentage
 *
 * Query Parameters:
 * - fiscalYear: Year to analyze (required)
 * - depotId: Filter by depot (UUID, optional for global view)
 *
 * @returns Cost variance with budget, actual, and status
 */
costingRoutes.get('/costing/variance', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  // Parse query parameters
  const fiscalYearParam = c.req.query('fiscalYear');
  const depotId = c.req.query('depotId');

  // Validate fiscal year (required)
  if (!fiscalYearParam) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'fiscalYear is required', requestId),
      400
    );
  }

  const fiscalYear = Number(fiscalYearParam);
  if (isNaN(fiscalYear) || fiscalYear < 2000 || fiscalYear > 2100) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'fiscalYear must be a valid year between 2000 and 2100',
        requestId
      ),
      400
    );
  }

  // Validate depotId if provided
  if (depotId && !isValidUuid(depotId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid depotId format', requestId),
      400
    );
  }

  try {
    const variance = await service.calculateVariance({
      fiscalYear,
      depotId: depotId || undefined,
    });

    // Map to API response format per spec 005.12
    return c.json(
      success(
        {
          fiscalYear: variance.fiscalYear,
          depotId: variance.depotId,
          depotCode: variance.depotCode || null,
          budget: {
            labor: Math.round(variance.budget.labor * 100) / 100,
            material: Math.round(variance.budget.material * 100) / 100,
            total: Math.round(variance.budget.total * 100) / 100,
          },
          actual: {
            labor: Math.round(variance.actual.labor * 100) / 100,
            material: Math.round(variance.actual.material * 100) / 100,
            total: Math.round(variance.actual.total * 100) / 100,
          },
          variance: {
            labor: Math.round(variance.variance.labor * 100) / 100,
            material: Math.round(variance.variance.material * 100) / 100,
            total: Math.round(variance.variance.total * 100) / 100,
            percentage: Math.round(variance.variance.percentage * 100) / 100,
          },
          status: variance.status,
          pmCompleted: variance.pmCompleted,
          calculatedAt: variance.calculatedAt.toISOString(),
        },
        { timing: { durationMs: getRequestDuration(c) } }
      )
    );
  } catch (err) {
    // Handle NotFoundError for missing cost baseline
    if (err instanceof Error && err.name === 'NotFoundError') {
      return c.json(
        error(
          ErrorCodes.NOT_FOUND,
          `Cost baseline not found for fiscal year ${fiscalYear}${depotId ? ` and depot ${depotId}` : ''}`,
          requestId
        ),
        404
      );
    }
    throw err;
  }
});

