     1→/**
     2→ * Export Routes
     3→ *
     4→ * REST endpoints for exporting PM schedules (Excel/CSV) and generating reports (PDF).
     5→ * Uses async job processing with status polling.
     6→ *
     7→ * Key endpoints:
     8→ * - POST /export/pm-schedule - Queue PM schedule export
     9→ * - POST /export/report - Queue report generation
    10→ * - GET /export/:jobId - Get export job status and download URL
    11→ * - GET /export/jobs - List export jobs for current user
    12→ *
    13→ * @see specs/005-api.md Section 5.15
    14→ */
    15→
    16→import { Hono } from 'hono';
    17→import {
    18→  success,
    19→  paginatedSuccess,
    20→  error,
    21→  parsePaginationQuery,
    22→  ErrorCodes,
    23→  type AppVariables,
    24→} from '../types';
    25→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    26→import {
    27→  getExportService,
    28→  type PmScheduleExportRequest,
    29→  type ReportExportRequest,
    30→  type ExportJobStatus,
    31→  type ReportType,
    32→} from '../../services/export';
    33→
    34→// Singleton service instance
    35→let exportService: ReturnType<typeof getExportService> | null = null;
    36→
    37→function getService(): ReturnType<typeof getExportService> {
    38→  if (!exportService) {
    39→    exportService = getExportService();
    40→  }
    41→  return exportService;
    42→}
    43→
    44→export const exportRoutes = new Hono<{ Variables: AppVariables }>();
    45→
    46→/**
    47→ * POST /export/pm-schedule
    48→ *
    49→ * Queue a PM schedule export job.
    50→ *
    51→ * Request Body:
    52→ * - format: Export format ('xlsx' or 'csv')
    53→ * - filters: Optional filters (depotId, fleetId, trainId, fromDate, toDate, status, pmTypeId, scenarioId)
    54→ * - columns: Optional list of columns to include
    55→ *
